import React from "react";
import { AiFillStar } from "@react-icons/all-files/ai/AiFillStar";

const Stars = () => {
  const Star = ({ selected = false }) => (
    <AiFillStar size={"30px"} color={selected ? "red" : "grey"} />
  );
  return <div>{Star}</div>;
};

export default Stars;
